var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"흠흐흠~ 오늘은 어떤 라면을 먹어 볼까......","JPN":"フフフ～ン、今日はどのラーメンにしようかな……","ENG":"Hmm, what kind of ramen should I eat today?","TWN":"哼哼哼～今天要吃什麼拉麵……"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"앗, 어서오세요~ 손님~","JPN":"あっ、いらっしゃいませ～♬","ENG":"Oh, welcome!","TWN":"啊，歡迎光臨～客人～"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"심심풀이 땅콩부터 수류탄까지 뭐~든 취급하는 편의점 아포칼립스입니다.","JPN":"チューインガムからミサイルまで♬コンビニアポカリプスへようこそ♬","ENG":"From peanuts to grenades, we've got everything you need here at Apocalypse!","TWN":"這裡是只要您有錢，從打發時間的花生米到手榴彈，什麼商品都可以買到的阿佛卡利斯便利商店。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"어머, 이번에 새로 부임했다는 사장님이시군요.","JPN":"あら、新しく赴任された社長さんですね。","ENG":"Oh, you must be the new CEO who joined recently.","TWN":"哎呀！我還以為是誰呢，原來是新老闆啊。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"저는 이 가게 아르바이트를 맡고 있는 세리나 크루라고 해요.","JPN":"私はこのお店のアルバイト、セリーナ・クルーです。","ENG":"My name is Serina Crew, a part-timer at this convenience store.","TWN":"我是這家店的打工店員瑟琳娜·克魯。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"저도 여기서 일을 시작한 지는 얼마 안 됐답니다.","JPN":"私もここで仕事を始めたばかりなんですよ。","ENG":"I just started working here recently as well.","TWN":"我也才在這裡工作沒多久。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 사장님과 입사 동기가 되려나요? 후훗.","JPN":"だから、あなたとは入社同期になるのかしら？　ふふっ♪","ENG":"I guess that makes us company buddies? Hah hah.","TWN":"那麼我和老闆算是同期進公司的員工囉？呵呵。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"네? 편의점 직원치곤 복장이 너무 화려하지 않냐고요?","JPN":"え？　コンビニのバイトにしては服装が派手すぎないかって？","ENG":"Huh? My outfit is too fancy for a convenience store clerk?","TWN":"什麼？您說這家便利商店的員工制服太華麗了嗎？"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"으음, 곤란하네요.","JPN":"う～ん、困りましたね。","ENG":"Mm, that's a bit awkward.","TWN":"嗯，這樣有點傷腦筋呢。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"나름 제 옷장에선 제일 저렴하고 서민적인 의상인데.","JPN":"これが私のクローゼットの中で、一番安くて庶民的な服なのに……","ENG":"This is the cheapest and the most ordinary outfit from my closet.","TWN":"這已經是我的衣櫃裡最便宜又最大眾的衣服了。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"아, 거기 진열된 소총들은 특별행사기간이라 탄약을 서비스로 드리고 있어요.","JPN":"ああ、そこに並べてある小銃は弾薬プレゼントキャンペーン中なんですよ。","ENG":"Oh, we're having a special sale on those rifles on display. Buy them today and we'll throw in the ammo for free.","TWN":"啊，那裡陳列的步槍在特別活動期間，會贈送免費彈藥喔。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"그 밖에도 매대에 올라와 있는 것들은 전부 편의점에서 직접 판매하는 것들이랍니다.","JPN":"他にも、棚に並べてあるものは全部コンビニの売り物なんです。","ENG":"And everything else displayed on the shelves is for sale.","TWN":"除此之外，櫃檯上所有的商品都是在便利商店中直接販售的。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"보급소에선 주기적으로 남는 상품들을 입고해 할인 판매하고 있으니,","JPN":"補給所では定期的に売れ残った商品を割引販売しているので、","ENG":"We also have periodic discount sales on overstocked items at the supply station.","TWN":"我們會定期購入補給站的商品貨物，並進行打折銷售。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"꼭 한 번 둘러보시길 권장 드려요.","JPN":"たまに覗いてみてくださいね～♪","ENG":"I recommend you take a look at them as well.","TWN":"請您務必參考看看。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SERINA_COFFIN_NULL_NULL","text":{"KOREA":"그럼 천천히 둘러보시고, 마음에 드는 게 있으시면 말씀해 주세요?","JPN":"それでは、ごゆっくりどうぞ。気に入った物があったら言ってくださいね。","ENG":"Take as much time as you want to look around, and come talk to me if you find anything that interests you.","TWN":"那麼您慢慢逛吧，有看到什麼喜歡的東西就跟我說。"},"stage":{"bg":"STORE2","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SERINA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};